// InlineKeyboardButton This object represents one button of an inline keyboard. Exactly one of the fields other than *text*, *icon\_custom\_emoji\_id*, and *style* must be used to specify the type of the button.
type InlineKeyboardButton struct {
	// CallbackData *Optional*. Data to be sent in a [callback query](https://core.telegram.org/bots/api/#callbackquery) to the bot when the button is pressed, 1-64 bytes
	CallbackData *string `json:"callback_data,omitempty"`

	// CallbackGame A placeholder, currently holds no information. Use [BotFather](https://t.me/botfather) to set up your game.
	CallbackGame *CallbackGame `json:"callback_game,omitempty"`

	// CopyText This object represents an inline keyboard button that copies specified text to the clipboard.
	CopyText *CopyTextButton `json:"copy_text,omitempty"`

	// IconCustomEmojiId *Optional*. Unique identifier of the custom emoji shown before the text of the button. Can only be used by bots that purchased additional usernames on [Fragment](https://fragment.com) or in the messages directly sent by the bot to private, group and supergroup chats if the owner of the bot has a Telegram Premium subscription.
	IconCustomEmojiId *string `json:"icon_custom_emoji_id,omitempty"`

	// LoginUrl This object represents a parameter of the inline keyboard button used to automatically authorize a user. Serves as a great replacement for the [Telegram Login Widget](https://core.telegram.org/widgets/login) when the user is coming from Telegram. All the user needs to do is tap/click a button and confirm that they want to log in:
	//
	// Telegram apps support these buttons as of [version 5.7](https://telegram.org/blog/privacy-discussions-web-bots#meet-seamless-web-bots).
	//
	// Sample bot: [@discussbot](https://t.me/discussbot)
	LoginUrl *LoginUrl `json:"login_url,omitempty"`

	// Pay *Optional*. Specify *True*, to send a [Pay button](https://core.telegram.org/bots/api/#payments). Substrings “⭐” and “XTR” in the buttons's text will be replaced with a Telegram Star icon.
	//
	// **NOTE:** This type of button **must** always be the first button in the first row and can only be used in invoice messages.
	Pay *bool `json:"pay,omitempty"`

	// Style *Optional*. Style of the button. Must be one of “danger” (red), “success” (green) or “primary” (blue). If omitted, then an app-specific style is used.
	Style *InlineKeyboardButtonStyle `json:"style,omitempty"`

	// SwitchInlineQuery *Optional*. If set, pressing the button will prompt the user to select one of their chats, open that chat and insert the bot's username and the specified inline query in the input field. May be empty, in which case just the bot's username will be inserted. Not supported for messages sent in channel direct messages chats and on behalf of a Telegram Business account.
	SwitchInlineQuery *string `json:"switch_inline_query,omitempty"`

	// SwitchInlineQueryChosenChat This object represents an inline button that switches the current user to inline mode in a chosen chat, with an optional default inline query.
	SwitchInlineQueryChosenChat *SwitchInlineQueryChosenChat `json:"switch_inline_query_chosen_chat,omitempty"`

	// SwitchInlineQueryCurrentChat *Optional*. If set, pressing the button will insert the bot's username and the specified inline query in the current chat's input field. May be empty, in which case only the bot's username will be inserted.
	//
	// This offers a quick way for the user to open your bot in inline mode in the same chat - good for selecting something from multiple options. Not supported in channels and for messages sent in channel direct messages chats and on behalf of a Telegram Business account.
	SwitchInlineQueryCurrentChat *string `json:"switch_inline_query_current_chat,omitempty"`

	// Text Label text on the button
	Text string `json:"text"`

	// Url *Optional*. HTTP or tg:// URL to be opened when the button is pressed. Links `tg://user?id=<user_id>` can be used to mention a user by their identifier without using a username, if this is allowed by their privacy settings.
	Url *string `json:"url,omitempty"`

	// WebApp Describes a [Web App](https://core.telegram.org/bots/webapps).
	WebApp *WebAppInfo `json:"web_app,omitempty"`
}

// InlineKeyboardButtonStyle *Optional*. Style of the button. Must be one of “danger” (red), “success” (green) or “primary” (blue). If omitted, then an app-specific style is used.
type InlineKeyboardButtonStyle string

// InlineKeyboardMarkup This object represents an [inline keyboard](https://core.telegram.org/bots/features#inline-keyboards) that appears right next to the message it belongs to.
