// Update This [object](https://core.telegram.org/bots/api/#available-types) represents an incoming update.
// At most **one** of the optional parameters can be present in any given update.
type Update struct {
	// BusinessConnection Describes the connection of the bot with a business account.
	BusinessConnection *BusinessConnection `json:"business_connection,omitempty"`

	// BusinessMessage This object represents a message.
	BusinessMessage *Message `json:"business_message,omitempty"`

	// CallbackQuery This object represents an incoming callback query from a callback button in an [inline keyboard](https://core.telegram.org/bots/features#inline-keyboards). If the button that originated the query was attached to a message sent by the bot, the field *message* will be present. If the button was attached to a message sent via the bot (in [inline mode](https://core.telegram.org/bots/api/#inline-mode)), the field *inline\_message\_id* will be present. Exactly one of the fields *data* or *game\_short\_name* will be present.
	CallbackQuery *CallbackQuery `json:"callback_query,omitempty"`

	// ChannelPost This object represents a message.
	ChannelPost *Message `json:"channel_post,omitempty"`

	// ChatBoost This object represents a boost added to a chat or changed.
	ChatBoost *ChatBoostUpdated `json:"chat_boost,omitempty"`

	// ChatJoinRequest Represents a join request sent to a chat.
	ChatJoinRequest *ChatJoinRequest `json:"chat_join_request,omitempty"`

	// ChatMember This object represents changes in the status of a chat member.
	ChatMember *ChatMemberUpdated `json:"chat_member,omitempty"`

	// ChosenInlineResult Represents a [result](https://core.telegram.org/bots/api/#inlinequeryresult) of an inline query that was chosen by the user and sent to their chat partner.
	ChosenInlineResult *ChosenInlineResult `json:"chosen_inline_result,omitempty"`

	// DeletedBusinessMessages This object is received when messages are deleted from a connected business account.
	DeletedBusinessMessages *BusinessMessagesDeleted `json:"deleted_business_messages,omitempty"`

	// EditedBusinessMessage This object represents a message.
	EditedBusinessMessage *Message `json:"edited_business_message,omitempty"`

	// EditedChannelPost This object represents a message.
	EditedChannelPost *Message `json:"edited_channel_post,omitempty"`

	// EditedMessage This object represents a message.
	EditedMessage *Message `json:"edited_message,omitempty"`

	// InlineQuery This object represents an incoming inline query. When the user sends an empty query, your bot could return some default or trending results.
	InlineQuery *InlineQuery `json:"inline_query,omitempty"`

	// Message This object represents a message.
	Message *Message `json:"message,omitempty"`

	// MessageReaction This object represents a change of a reaction on a message performed by a user.
	MessageReaction *MessageReactionUpdated `json:"message_reaction,omitempty"`

	// MessageReactionCount This object represents reaction changes on a message with anonymous reactions.
	MessageReactionCount *MessageReactionCountUpdated `json:"message_reaction_count,omitempty"`

	// MyChatMember This object represents changes in the status of a chat member.
	MyChatMember *ChatMemberUpdated `json:"my_chat_member,omitempty"`

	// Poll This object contains information about a poll.
	Poll *Poll `json:"poll,omitempty"`

	// PollAnswer This object represents an answer of a user in a non-anonymous poll.
	PollAnswer *PollAnswer `json:"poll_answer,omitempty"`

	// PreCheckoutQuery This object contains information about an incoming pre-checkout query.
	PreCheckoutQuery *PreCheckoutQuery `json:"pre_checkout_query,omitempty"`

	// PurchasedPaidMedia This object contains information about a paid media purchase.
	PurchasedPaidMedia *PaidMediaPurchased `json:"purchased_paid_media,omitempty"`

	// RemovedChatBoost This object represents a boost removed from a chat.
	RemovedChatBoost *ChatBoostRemoved `json:"removed_chat_boost,omitempty"`

	// ShippingQuery This object contains information about an incoming shipping query.
	ShippingQuery *ShippingQuery `json:"shipping_query,omitempty"`

	// UpdateId The update's unique identifier. Update identifiers start from a certain positive number and increase sequentially. This identifier becomes especially handy if you're using [webhooks](https://core.telegram.org/bots/api/#setwebhook), since it allows you to ignore repeated updates or to restore the correct update sequence, should they get out of order. If there are no new updates for at least a week, then identifier of the next update will be chosen randomly instead of sequentially.
	UpdateId int `json:"update_id"`
}

// User This object represents a Telegram user or bot.
type User struct {
	// AddedToAttachmentMenu *Optional*. *True*, if this user added the bot to the attachment menu
	AddedToAttachmentMenu *bool `json:"added_to_attachment_menu,omitempty"`

	// AllowsUsersToCreateTopics *Optional*. *True*, if the bot allows users to create and delete topics in private chats. Returned only in [getMe](https://core.telegram.org/bots/api/#getme).
	AllowsUsersToCreateTopics *bool `json:"allows_users_to_create_topics,omitempty"`

	// CanConnectToBusiness *Optional*. *True*, if the bot can be connected to a Telegram Business account to receive its messages. Returned only in [getMe](https://core.telegram.org/bots/api/#getme).
	CanConnectToBusiness *bool `json:"can_connect_to_business,omitempty"`

	// CanJoinGroups *Optional*. *True*, if the bot can be invited to groups. Returned only in [getMe](https://core.telegram.org/bots/api/#getme).
	CanJoinGroups *bool `json:"can_join_groups,omitempty"`

	// CanReadAllGroupMessages *Optional*. *True*, if [privacy mode](https://core.telegram.org/bots/features#privacy-mode) is disabled for the bot. Returned only in [getMe](https://core.telegram.org/bots/api/#getme).
	CanReadAllGroupMessages *bool `json:"can_read_all_group_messages,omitempty"`

	// FirstName User's or bot's first name
	FirstName string `json:"first_name"`

	// HasMainWebApp *Optional*. *True*, if the bot has a main Web App. Returned only in [getMe](https://core.telegram.org/bots/api/#getme).
	HasMainWebApp *bool `json:"has_main_web_app,omitempty"`

	// HasTopicsEnabled *Optional*. *True*, if the bot has forum topic mode enabled in private chats. Returned only in [getMe](https://core.telegram.org/bots/api/#getme).
	HasTopicsEnabled *bool `json:"has_topics_enabled,omitempty"`

	// Id Unique identifier for this user or bot. This number may have more than 32 significant bits and some programming languages may have difficulty/silent defects in interpreting it. But it has at most 52 significant bits, so a 64-bit integer or double-precision float type are safe for storing this identifier.
	Id int `json:"id"`

	// IsBot *True*, if this user is a bot
	IsBot bool `json:"is_bot"`

	// IsPremium *Optional*. *True*, if this user is a Telegram Premium user
	IsPremium *bool `json:"is_premium,omitempty"`

	// LanguageCode *Optional*. [IETF language tag](https://en.wikipedia.org/wiki/IETF_language_tag) of the user's language
	LanguageCode *string `json:"language_code,omitempty"`

	// LastName *Optional*. User's or bot's last name
	LastName *string `json:"last_name,omitempty"`

	// SupportsInlineQueries *Optional*. *True*, if the bot supports inline queries. Returned only in [getMe](https://core.telegram.org/bots/api/#getme).
	SupportsInlineQueries *bool `json:"supports_inline_queries,omitempty"`

	// Username *Optional*. User's or bot's username
	Username *string `json:"username,omitempty"`
}

