// PostCreateInvoiceLinkJSONBody defines parameters for PostCreateInvoiceLink.
type PostCreateInvoiceLinkJSONBody struct {
	// BusinessConnectionId Unique identifier of the business connection on behalf of which the link will be created. For payments in [Telegram Stars](https://t.me/BotNews/90) only.
	BusinessConnectionId *string `json:"business_connection_id,omitempty"`

	// Currency Three-letter ISO 4217 currency code, see [more on currencies](https://core.telegram.org/bots/payments#supported-currencies). Pass “XTR” for payments in [Telegram Stars](https://t.me/BotNews/90).
	Currency string `json:"currency"`

	// Description Product description, 1-255 characters
	Description string `json:"description"`

	// IsFlexible Pass *True* if the final price depends on the shipping method. Ignored for payments in [Telegram Stars](https://t.me/BotNews/90).
	IsFlexible *bool `json:"is_flexible,omitempty"`

	// MaxTipAmount The maximum accepted amount for tips in the *smallest units* of the currency (integer, **not** float/double). For example, for a maximum tip of `US$ 1.45` pass `max_tip_amount = 145`. See the *exp* parameter in [currencies.json](https://core.telegram.org/bots/payments/currencies.json), it shows the number of digits past the decimal point for each currency (2 for the majority of currencies). Defaults to 0. Not supported for payments in [Telegram Stars](https://t.me/BotNews/90).
	MaxTipAmount *int `json:"max_tip_amount,omitempty"`

	// NeedEmail Pass *True* if you require the user's email address to complete the order. Ignored for payments in [Telegram Stars](https://t.me/BotNews/90).
	NeedEmail *bool `json:"need_email,omitempty"`

	// NeedName Pass *True* if you require the user's full name to complete the order. Ignored for payments in [Telegram Stars](https://t.me/BotNews/90).
	NeedName *bool `json:"need_name,omitempty"`

	// NeedPhoneNumber Pass *True* if you require the user's phone number to complete the order. Ignored for payments in [Telegram Stars](https://t.me/BotNews/90).
	NeedPhoneNumber *bool `json:"need_phone_number,omitempty"`

	// NeedShippingAddress Pass *True* if you require the user's shipping address to complete the order. Ignored for payments in [Telegram Stars](https://t.me/BotNews/90).
	NeedShippingAddress *bool `json:"need_shipping_address,omitempty"`

	// Payload Bot-defined invoice payload, 1-128 bytes. This will not be displayed to the user, use it for your internal processes.
	Payload string `json:"payload"`

	// PhotoHeight Photo height
	PhotoHeight *int `json:"photo_height,omitempty"`

	// PhotoSize Photo size in bytes
	PhotoSize *int `json:"photo_size,omitempty"`

	// PhotoUrl URL of the product photo for the invoice. Can be a photo of the goods or a marketing image for a service.
	PhotoUrl *string `json:"photo_url,omitempty"`

	// PhotoWidth Photo width
	PhotoWidth *int `json:"photo_width,omitempty"`

	// Prices Price breakdown, a JSON-serialized list of components (e.g. product price, tax, discount, delivery cost, delivery tax, bonus, etc.). Must contain exactly one item for payments in [Telegram Stars](https://t.me/BotNews/90).
	Prices []LabeledPrice `json:"prices"`

	// ProviderData JSON-serialized data about the invoice, which will be shared with the payment provider. A detailed description of required fields should be provided by the payment provider.
	ProviderData *string `json:"provider_data,omitempty"`

	// ProviderToken Payment provider token, obtained via [@BotFather](https://t.me/botfather). Pass an empty string for payments in [Telegram Stars](https://t.me/BotNews/90).
	ProviderToken *string `json:"provider_token,omitempty"`

	// SendEmailToProvider Pass *True* if the user's email address should be sent to the provider. Ignored for payments in [Telegram Stars](https://t.me/BotNews/90).
	SendEmailToProvider *bool `json:"send_email_to_provider,omitempty"`

	// SendPhoneNumberToProvider Pass *True* if the user's phone number should be sent to the provider. Ignored for payments in [Telegram Stars](https://t.me/BotNews/90).
	SendPhoneNumberToProvider *bool `json:"send_phone_number_to_provider,omitempty"`

	// SubscriptionPeriod The number of seconds the subscription will be active for before the next payment. The currency must be set to “XTR” (Telegram Stars) if the parameter is used. Currently, it must always be 2592000 (30 days) if specified. Any number of subscriptions can be active for a given bot at the same time, including multiple concurrent subscriptions from the same user. Subscription price must no exceed 10000 Telegram Stars.
	SubscriptionPeriod *int `json:"subscription_period,omitempty"`

	// SuggestedTipAmounts A JSON-serialized array of suggested amounts of tips in the *smallest units* of the currency (integer, **not** float/double). At most 4 suggested tip amounts can be specified. The suggested tip amounts must be positive, passed in a strictly increased order and must not exceed *max\_tip\_amount*.
	SuggestedTipAmounts *[]int `json:"suggested_tip_amounts,omitempty"`

	// Title Product name, 1-32 characters
	Title string `json:"title"`
}

